class MinHeap {
    constructor() { this.a = []; }
    push(item) {
        const a = this.a;
        a.push(item);
        let i = a.length - 1;
        while (i > 0) {
            const p = (i - 1) >> 1;
            if (cmp(a[p], a[i]) > 0) { const t = a[p]; a[p] = a[i]; a[i] = t; i = p; } else break;
        }
    }
    pop() {
        const a = this.a;
        const top = a[0];
        const last = a.pop();
        if (a.length) {
            a[0] = last;
            let i = 0;
            while (true) {
                let l = 2 * i + 1, r = 2 * i + 2, s = i;
                if (l < a.length && cmp(a[l], a[s]) < 0) s = l;
                if (r < a.length && cmp(a[r], a[s]) < 0) s = r;
                if (s === i) break;
                const t = a[s]; a[s] = a[i]; a[i] = t;
                i = s;
            }
        }
        return top;
    }
}
function cmp(x, y) {
    if (x[0] < y[0]) return -1;
    if (x[0] > y[0]) return 1;
    return x[1] - y[1];
}
function modpow(base, exp, mod) {
    base = ((base % mod) + mod) % mod;
    let result = 1n;
    let b = base;
    let e = exp;
    while (e > 0n) {
        if (e & 1n) result = (result * b) % mod;
        b = (b * b) % mod;
        e >>= 1n;
    }
    return result;
}
var getFinalState = function(nums, k, multiplier) {
    const MOD = 1000000007n;
    const n = nums.length;
    if (multiplier === 1 || k <= 0) {
        return nums.map(x => Number(((BigInt(x) % MOD) + MOD) % MOD));
    }
    const vals = nums.map(x => BigInt(x));
    const opcount = new Array(n).fill(0n);
    const heap = new MinHeap();
    for (let i = 0; i < n; i++) heap.push([vals[i], i]);

    let opsDone = 0;
    const capRamp = Math.min(k, n * 80 + 200);
    const history = [];
    let periodicOrder = null;

    while (opsDone < capRamp) {
        const [v, i] = heap.pop();
        vals[i] = v * BigInt(multiplier);
        opcount[i] += 1n;
        opsDone += 1;
        heap.push([vals[i], i]);
        history.push(i);
        if (history.length >= 2 * n) {
            const last = history.slice(-n);
            const prev = history.slice(-2 * n, -n);
            let same = true;
            for (let x = 0; x < n; x++) { if (last[x] !== prev[x]) { same = false; break; } }
            if (same) {
                const setLast = new Set(last);
                if (setLast.size === n) {
                    periodicOrder = last;
                    break;
                }
            }
        }
    }

    if (periodicOrder !== null) {
        const remaining = k - opsDone;
        const fullCycles = BigInt(Math.floor(remaining / n));
        const leftover = remaining % n;
        for (let i = 0; i < n; i++) opcount[i] += fullCycles;
        for (let idx = 0; idx < leftover; idx++) opcount[periodicOrder[idx]] += 1n;
    }

    return nums.map((x, i) => Number((BigInt(x) * modpow(BigInt(multiplier), opcount[i], MOD)) % MOD));
};
